// One item per channel feed, with a direct URL and an rss2json fallback URL.
const FEEDS = [
  { channel: 'a16z', id: 'UC9cn0TuPq4dnbTY-CBsm8XA' },
  { channel: 'Y Combinator', id: 'UCcefcZRL2oaA_uBNeo5UOWg' },
  { channel: 'SaaStr AI', id: 'UCwOILzAcxK5CM2M7oRBuWSg' },
  { channel: "Lenny's Podcast", id: 'UC6t1O76G0jYXOAoYCm153dA' },
  { channel: 'Peter H. Diamandis', id: 'UCvxm0qTrGN_1LMYgUaftWyQ' },
  { channel: 'How I AI', id: 'UCRYY7IEbkHLH_ScJCu9eWDQ' },
  { channel: 'Aakash Gupta', id: 'UCsHBhXybRz2CCfpU0hWp7ow' },
  { channel: 'Every', id: 'UCjIMtrzxYc0lblGhmOgC_CA' }
];
const mode = (items[0] && items[0].json && items[0].json.mode) || 'digest';
return FEEDS.map(f => {
  const url = 'https://www.youtube.com/feeds/videos.xml?channel_id=' + f.id;
  return { json: {
    mode,
    channel: f.channel,
    feedUrl: url,
    fallbackUrl: 'https://api.rss2json.com/v1/api.json?rss_url=' + encodeURIComponent(url)
  }};
});

// Normalize direct-XML + rss2json results, update the persistent ledger
// (workflowStaticData): new videos -> status 'discovered'; track per-feed health.
const sd = $getWorkflowStaticData('global');
if (!sd.videos) sd.videos = {};
if (!sd.feedHealth) sd.feedHealth = {};
const now = Date.now();

const feeds = $('Split feeds').all().map(i => i.json);
const N = feeds.length;
const mode = (feeds[0] && feeds[0].mode) || 'digest';

// optional ops via webhook query: ?lookbackHours=96&markSent=id1,id2
let ops = {};
try { ops = $('Webhook trigger').first().json.query || {}; } catch (e) {}
const lookbackH = Math.max(1, Math.min(240, Number(ops.lookbackHours) || 72));
const cutoffMs = now - lookbackH * 3600 * 1000;
if (ops.markSent) {
  for (const id of String(ops.markSent).split(',').map(s => s.trim()).filter(Boolean)) {
    sd.videos[id] = Object.assign({}, sd.videos[id], { videoId: id, status: 'sent', sentAtMs: now, seeded: true });
  }
}

const decode = s => (s || '').replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&quot;/g, '"').replace(/&#39;/g, "'");

const okFeeds = new Set();
const errNotes = {};
const candidates = new Map();
function addCandidate(v) {
  if (!v.videoId) return;
  if (!candidates.has(v.videoId)) candidates.set(v.videoId, v);
}

items.forEach((it, idx) => {
  const feed = feeds[idx % N] || {};
  const isFallback = idx >= N;
  const j = it.json || {};
  if (j.error) {
    if (!okFeeds.has(feed.channel)) errNotes[feed.channel] = (isFallback ? 'fallback: ' : 'direct: ') + ((j.error.message || 'fetch failed') + '').slice(0, 160);
    return;
  }
  const xml = typeof j.data === 'string' ? j.data : (typeof j.body === 'string' ? j.body : '');
  if (xml && xml.indexOf('<entry') !== -1) {
    okFeeds.add(feed.channel);
    for (const e of xml.split('<entry>').slice(1)) {
      const vid = (e.match(/<yt:videoId>([^<]+)<\/yt:videoId>/) || [])[1];
      if (!vid) continue;
      const title = decode((e.match(/<title>([^<]*)<\/title>/) || [])[1] || '');
      const link = (e.match(/<link[^>]*rel="alternate"[^>]*href="([^"]+)"/) || [])[1] || ('https://www.youtube.com/watch?v=' + vid);
      const pub = (e.match(/<published>([^<]+)<\/published>/) || [])[1];
      addCandidate({ videoId: vid, title, url: link, published: pub ? new Date(pub).getTime() : null, channelName: feed.channel });
    }
    return;
  }
  if (j.status === 'ok' && Array.isArray(j.items)) {
    okFeeds.add(feed.channel);
    for (const e of j.items) {
      let vid = ((e.guid || '').match(/yt:video:([\w-]+)/) || [])[1];
      if (!vid) vid = ((e.link || '').match(/[?&]v=([\w-]+)/) || [])[1] || ((e.link || '').match(/\/shorts\/([\w-]+)/) || [])[1];
      if (!vid) continue;
      let pubMs = null;
      if (e.pubDate) {
        const s = String(e.pubDate).trim();
        pubMs = new Date(/[zZ]$|[+-]\d\d:?\d\d$/.test(s) ? s : s.replace(' ', 'T') + 'Z').getTime();
        if (isNaN(pubMs)) pubMs = null;
      }
      addCandidate({ videoId: vid, title: (e.title || '').toString(), url: e.link || ('https://www.youtube.com/watch?v=' + vid), published: pubMs, channelName: feed.channel });
    }
    return;
  }
  if (!okFeeds.has(feed.channel)) errNotes[feed.channel] = (isFallback ? 'fallback: ' : 'direct: ') + 'unrecognized response';
});

for (const f of feeds) {
  const h = sd.feedHealth[f.channel] || {};
  if (okFeeds.has(f.channel)) { h.lastOkMs = now; delete h.lastErrNote; }
  else { h.lastErrMs = now; h.lastErrNote = errNotes[f.channel] || 'failed'; }
  sd.feedHealth[f.channel] = h;
}

let newCount = 0;
for (const v of candidates.values()) {
  if (v.published && v.published < cutoffMs) continue;
  const urlL = (v.url || '').toLowerCase();
  if (urlL.includes('/shorts/') || /#shorts/i.test(v.title || '')) continue;
  if (sd.videos[v.videoId]) continue;
  sd.videos[v.videoId] = { videoId: v.videoId, title: v.title, url: v.url, published: v.published, channelName: v.channelName, status: 'discovered', firstSeenMs: now };
  newCount++;
}

// prune ledger entries older than 14 days
const pruneMs = now - 14 * 24 * 3600 * 1000;
for (const [id, v] of Object.entries(sd.videos)) {
  const ref = v.published || v.firstSeenMs || 0;
  if (ref && ref < pruneMs) delete sd.videos[id];
}

// channels with no successful fetch for 36h+ (on either path)
const dark = [];
for (const f of feeds) {
  const h = sd.feedHealth[f.channel] || {};
  if ((now - (h.lastOkMs || 0) > 36 * 3600 * 1000) && h.lastErrMs) {
    dark.push(f.channel);
  }
}
const healthWarning = dark.length ? '⚠️ Feeds failing for 36h+: ' + dark.join(', ') : '';

const unsent = Object.values(sd.videos).filter(v => v.status === 'discovered').length;
return [{ json: { mode, newCount, unsent, feedsOk: okFeeds.size, feedsTotal: N, healthWarning, lookbackHours: lookbackH } }];

// Emit one item per ledger video still awaiting delivery (oldest first, capped).
const CAP = 15;
const sd = $getWorkflowStaticData('global');
const all = Object.values(sd.videos || {}).filter(v => v.status === 'discovered');
let hw = '';
try { hw = $('Parse + discover').first().json.healthWarning || ''; } catch (e) {}
if (!all.length) return [{ json: { _noNew: true, _healthWarning: hw } }];
all.sort((a, b) => (a.published || a.firstSeenMs || 0) - (b.published || b.firstSeenMs || 0));
const batch = all.slice(0, CAP);
if (all.length > CAP) {
  hw = (hw ? hw + '\n' : '') + '⏭ ' + (all.length - CAP) + ' more video(s) queued for the next digest.';
}
return batch.map(v => ({ json: {
  videoId: v.videoId,
  title: v.title || '',
  url: v.url || '',
  published: v.published || null,
  firstSeenMs: v.firstSeenMs || null,
  channelName: v.channelName || '',
  _healthWarning: hw
}}));

function decodeEntities(s) {
  if (!s || typeof s !== 'string') return s;
  return s.replace(/&amp;/g,'&').replace(/&lt;/g,'<').replace(/&gt;/g,'>')
          .replace(/&quot;/g,'"').replace(/&#39;/g,"'").replace(/&nbsp;/g,' ');
}

function toSeconds(seg) {
  let v = null;
  if (seg.start != null)        v = Number(seg.start);
  else if (seg.offset != null)  v = Number(seg.offset);
  else if (seg.tStartMs != null)v = Number(seg.tStartMs) / 1000;
  else if (seg.startMs != null) v = Number(seg.startMs) / 1000;
  else if (seg.begin != null)   v = Number(seg.begin);
  else if (seg.startTime!=null) v = Number(seg.startTime);
  if (v == null || isNaN(v)) return null;
  if (v > 100000) v = v / 1000;
  return Math.max(0, Math.floor(v));
}

function normTok(s) {
  return (s || '').toString().toLowerCase().replace(/[^a-z0-9\s]/g, ' ').replace(/\s+/g, ' ').trim();
}

function montageEndIndex(segments) {
  const REGION = 180;
  const GAP    = 120;
  const MIN_RECUR = 3;
  const LONG   = 600;
  const MAX_FRAC = 0.4;

  const dur = segments.reduce((m, s) => (s.t != null && s.t > m ? s.t : m), 0);
  if (dur <= LONG) return -1;

  const toks = [];
  for (let i = 0; i < segments.length; i++) {
    const t = segments[i].t;
    for (const w of normTok(segments[i].text).split(' ')) if (w) toks.push({ w, t });
  }
  const grams = new Map();
  for (let i = 0; i + 3 < toks.length; i++) {
    if (toks[i].t == null) continue;
    const key = toks[i].w + ' ' + toks[i+1].w + ' ' + toks[i+2].w + ' ' + toks[i+3].w;
    let arr = grams.get(key); if (!arr) { arr = []; grams.set(key, arr); }
    arr.push(toks[i].t);
  }
  function recurs(seg) {
    if (seg.t == null || seg.t >= REGION) return false;
    const w = normTok(seg.text).split(' ').filter(Boolean);
    if (w.length < 4) return false;
    for (let i = 0; i + 3 < w.length; i++) {
      const arr = grams.get(w[i] + ' ' + w[i+1] + ' ' + w[i+2] + ' ' + w[i+3]);
      if (arr && arr.some(t => t >= seg.t + GAP)) return true;
    }
    return false;
  }

  let lastIdx = -1, count = 0;
  for (let i = 0; i < segments.length; i++) {
    const s = segments[i];
    if (s.t != null && s.t >= REGION) break;
    if (recurs(s)) { lastIdx = i; count++; }
  }
  if (count < MIN_RECUR) return -1;
  if (lastIdx + 1 > segments.length * MAX_FRAC) return -1;
  return lastIdx;
}

const out = [];
for (const it of items) {
  const j = it.json || {};
  const meta = j.meta || {};

  let segs = [];
  if (Array.isArray(j)) segs = j;
  else if (Array.isArray(j.transcript)) segs = j.transcript;
  else if (Array.isArray(j.data)) segs = j.data;
  else if (Array.isArray(j.result)) segs = j.result;
  else {
    for (const k of Object.keys(j)) {
      if (Array.isArray(j[k]) && j[k].length && typeof j[k][0]?.text === 'string') { segs = j[k]; break; }
    }
  }

  let segments = [];
  for (const s of segs) {
    let text = decodeEntities((s.text || s.caption || '').toString());
    text = text.replace(/>>/g, ' ').replace(/\s+/g, ' ').trim();
    if (!text) continue;
    segments.push({ t: toSeconds(s), text });
  }

  const mEnd = montageEndIndex(segments);
  if (mEnd >= 0) segments = segments.slice(mEnd + 1);

  const joined = segments.length
    ? segments.map(s => s.text).join(' ').replace(/\s+/g,' ').trim()
    : '';

  out.push({
    json: {
      videoId: meta.videoId || j.videoId || j.id || '',
      title:   meta.title   || j.title   || '',
      url:     meta.url     || j.url     || j.link || '',
      channelName: meta.channelName || '',
      published: meta.published || null,
      firstSeenMs: meta.firstSeenMs || null,
      transcriptText: (joined || '').trim(),
      segments
    }
  });
}
return out;

// Build insightsObj { videoTitle, videoUrl, summary, insights[{headline,detail,anchorQuote,tSeconds,link}] }
// Resolves a real timestamp per anchorQuote from `segments`, defeating cold-open teasers.

function coerceObjectFrom(any) {
  if (!any) return null;
  if (typeof any === 'object') return any;
  if (typeof any === 'string') {
    try { return JSON.parse(any); } catch {}
    const m = any.match(/\{[\s\S]*\}$/);
    if (m) { try { return JSON.parse(m[0]); } catch {} }
  }
  return null;
}

function norm(s) {
  return (s || '').toString().toLowerCase().replace(/[^a-z0-9\s]/g, ' ').replace(/\s+/g, ' ').trim();
}

function buildCharIndex(segments) {
  const charSeg = []; let concat = '';
  for (let i = 0; i < segments.length; i++) {
    const t = norm(segments[i].text);
    if (!t) continue;
    if (concat) { concat += ' '; charSeg.push(i); }
    for (let c = 0; c < t.length; c++) { concat += t[c]; charSeg.push(i); }
  }
  return { concat, charSeg };
}

function tokenStream(segments) {
  const toks = [];
  for (let i = 0; i < segments.length; i++) {
    const t = norm(segments[i].text); if (!t) continue;
    for (const w of t.split(' ')) if (w) toks.push({ w, seg: i });
  }
  return toks;
}

function startSec(segments, segIdx) {
  for (let i = segIdx; i >= 0; i--) if (segments[i] && segments[i].t != null) return segments[i].t;
  for (let i = segIdx; i < segments.length; i++) if (segments[i] && segments[i].t != null) return segments[i].t;
  return null;
}

function resolveTimestamp(anchor, segments) {
  if (!anchor || !Array.isArray(segments) || !segments.length) return null;
  const a = norm(anchor);
  const at = a.split(' ').filter(Boolean);
  if (at.length < 2) return null;

  const { concat, charSeg } = buildCharIndex(segments);
  const videoDuration = segments.reduce((m, s) => (s.t != null && s.t > m ? s.t : m), 0);

  function occurrences(needle) {
    const res = []; let from = 0, i;
    while ((i = concat.indexOf(needle, from)) >= 0) { res.push(startSec(segments, charSeg[i])); from = i + 1; }
    return res.filter(t => t != null);
  }
  function pick(secs) {
    if (!secs.length) return null;
    const uniq = Array.from(new Set(secs)).sort((x, y) => x - y);
    const TEASER = 90, LONG = 600;
    if (uniq.length >= 2 && uniq[0] < TEASER && videoDuration > LONG) {
      const later = uniq.find(t => t >= TEASER);
      return later != null ? later : uniq[uniq.length - 1];
    }
    return uniq[0];
  }

  let secs = occurrences(a);
  if (secs.length) return pick(secs);

  for (let n = Math.min(at.length, 8); n >= 3; n--) {
    secs = occurrences(at.slice(0, n).join(' '));
    if (secs.length) return pick(secs);
  }

  const toks = tokenStream(segments);
  const want = new Set(at);
  const L = at.length;
  const scored = []; let bestScore = 0;
  for (let i = 0; i < toks.length; i++) {
    const end = Math.min(toks.length, i + L);
    const local = new Set(); let score = 0;
    for (let k = i; k < end; k++) {
      if (want.has(toks[k].w) && !local.has(toks[k].w)) { score++; local.add(toks[k].w); }
    }
    if (score > bestScore) bestScore = score;
    if (score / L >= 0.6) scored.push({ score, seg: toks[i].seg });
  }
  if (bestScore / L >= 0.6) {
    const top = scored.filter(s => s.score === bestScore)
                      .map(s => startSec(segments, s.seg))
                      .filter(t => t != null);
    if (top.length) return pick(top);
  }
  return null;
}

function addTimestamp(url, sec) {
  if (sec == null || !url) return url || '';
  const s = Math.max(0, Math.floor(sec));
  const sep = url.includes('?') ? '&' : '?';
  return url + sep + 't=' + s;
}

const out = [];
for (const it of items) {
  const row = it.json || {};
  const segments = Array.isArray(row.segments) ? row.segments : [];
  const inputTitle = row.title || row.videoTitle || row.meta?.title || '';
  const inputUrl   = row.url   || row.videoUrl   || row.meta?.url   || '';

  const raw =
    row?.choices?.[0]?.message?.content ||
    row?.message?.content ||
    row?.response ||
    row?.body ||
    (typeof row === 'string' ? row : null);

  let parsed = coerceObjectFrom(raw) || {};
  parsed.videoTitle = (parsed.videoTitle || inputTitle || '').toString().trim();
  parsed.videoUrl   = (parsed.videoUrl   || inputUrl   || '').toString().trim();

  let summary = '';
  if (typeof parsed.summary === 'string') summary = parsed.summary.trim();
  else if (typeof parsed.description === 'string') summary = parsed.description.trim();

  const rawInsights = Array.isArray(parsed.insights) ? parsed.insights : [];
  const conv = rawInsights.map(item => {
    if (!item) return null;
    if (typeof item === 'string') return { headline: item.replace(/\s+/g,' ').trim(), detail: '', anchorQuote: '' };
    if (typeof item === 'object') {
      const headline    = (item.headline || item.claim || item.text || item.insight || '').toString().replace(/\s+/g,' ').trim();
      const detail      = (item.detail || item.explanation || item.why || item.body || '').toString().replace(/\s+/g,' ').trim();
      const anchorQuote = (item.anchorQuote || item.quote || item.anchor || '').toString().replace(/\s+/g,' ').trim();
      if (!headline && !detail) return null;
      return { headline, detail, anchorQuote };
    }
    return null;
  }).filter(Boolean);

  const seenH = new Set(); const deduped = [];
  for (const x of conv) {
    const key = x.headline.toLowerCase();
    if (key && seenH.has(key)) continue;
    if (key) seenH.add(key);
    deduped.push(x);
    if (deduped.length >= 8) break;
  }

  for (const x of deduped) {
    const sec = resolveTimestamp(x.anchorQuote, segments);
    x.tSeconds = (sec == null ? null : sec);
    x.link = (sec == null ? '' : addTimestamp(parsed.videoUrl, sec));
  }

  if (!summary && row.transcriptText && row.transcriptText.length) {
    const t = row.transcriptText.replace(/\s+/g,' ').trim();
    const sentences = t.match(/[^.!?]+[.!?]+|[^.!?]+$/g) || [];
    summary = sentences.slice(0, 2).join(' ').trim();
    if (summary.length > 320) summary = summary.slice(0, 317) + '…';
  }

  const guests = Array.isArray(parsed.guests)
    ? parsed.guests.filter(g => typeof g === 'string' && g.trim()).map(g => g.trim())
    : [];
  const channelName = (row.meta?.channelName || row.channelName || '').toString().trim();
  const final = {
    videoTitle: parsed.videoTitle || '',
    videoUrl: parsed.videoUrl || '',
    channelName,
    guests,
    summary: summary || '',
    insights: deduped
  };
  out.push({ json: { ...row, insightsObj: final } });
}

return out;

// Videos without a transcript: younger than 36h stay in the ledger and are
// retried at the next digest (_omit); older ones go out link-only so nothing
// is ever silently dropped.
const now = Date.now();
const MAX_WAIT_MS = 36 * 3600 * 1000;
const out = [];
for (const it of items) {
  const j = it.json || {};
  const ref = Number(j.published) || Number(j.firstSeenMs) || 0;
  const age = ref ? (now - ref) : Infinity;
  if (age < MAX_WAIT_MS) {
    out.push({ json: { _omit: true, _pending: true, videoId: j.videoId, title: j.title, channelName: j.channelName } });
  } else {
    out.push({ json: {
      videoId: j.videoId,
      title: j.title,
      url: j.url,
      channelName: j.channelName,
      published: j.published,
      _linkOnly: true,
      insightsObj: {
        videoTitle: j.title,
        videoUrl: j.url,
        channelName: j.channelName,
        guests: [],
        summary: 'No transcript available — link only.',
        insights: []
      }
    }});
  }
}
return out;

// Build email digest from insightsObj items. Items flagged _omit are pending
// (no transcript yet) and excluded; they are counted in the footer.
const MAX_BULLETS = 12;

function esc(s) {
  return (s || '').toString().replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
}
function hhmmss(sec) {
  if (sec == null || isNaN(sec)) return '';
  sec = Math.floor(sec);
  const h = Math.floor(sec/3600), m = Math.floor((sec%3600)/60), s = sec%60;
  const mm = String(m).padStart(2,'0'), ss = String(s).padStart(2,'0');
  return h ? `${h}:${mm}:${ss}` : `${m}:${ss}`;
}
function normalizeInsights(v) {
  if (!Array.isArray(v)) return [];
  return v.map(x => {
    if (typeof x === 'string') return { headline: x.trim(), detail: '', link: '', tSeconds: null };
    if (x && typeof x === 'object') return {
      headline: (x.headline || x.claim || x.text || x.insight || '').toString().trim(),
      detail:   (x.detail   || x.explanation || x.why || '').toString().trim(),
      link:     (x.link || '').toString().trim(),
      tSeconds: (x.tSeconds == null ? null : Number(x.tSeconds))
    };
    return { headline: '', detail: '', link: '', tSeconds: null };
  }).filter(x => x.headline || x.detail);
}

const videos = [];
const seen = new Set();
let pending = 0;

for (const it of items) {
  const row = it.json || {};
  if (row._omit) { if (row._pending) pending++; continue; }
  const obj = row.insightsObj;
  if (!obj) continue;

  const title = (obj.videoTitle || row.videoTitle || row.title || 'Untitled').toString();
  const url   = (obj.videoUrl   || row.videoUrl   || row.url || '').toString();
  const key   = (url || title).toLowerCase();
  if (seen.has(key)) continue;
  seen.add(key);

  const summary  = (obj.summary || '').toString().trim();
  const insights = normalizeInsights(obj.insights).slice(0, MAX_BULLETS);
  const channelName = (obj.channelName || row.channelName || '').toString().trim();
  const guests      = Array.isArray(obj.guests) ? obj.guests.filter(g => typeof g === 'string' && g.trim()) : [];
  videos.push({ title, url, channelName, guests, summary, insights });
}

let hw = '';
try { hw = ($('Load unsent').first().json._healthWarning || '').toString(); } catch (e) {}

// ---- Markdown ----
let md = '# Daily Podcast Insights\n\n';
md += `Total videos: ${videos.length}\n\n`;
for (const v of videos) {
  const mdHeading = v.channelName ? `${v.channelName} · ${v.title}` : v.title;
  md += `## ${mdHeading}\n`;
  if (v.url) md += `${v.url}\n`;
  if (v.guests && v.guests.length) md += `\n_with ${v.guests.join(', ')}_\n`;
  if (v.summary) md += `\n${v.summary}\n`;
  if (v.insights.length) {
    md += '\n';
    for (const s of v.insights) {
      const ts = s.tSeconds != null ? ` (▶ ${hhmmss(s.tSeconds)})` : '';
      if (s.link) md += `- [**${s.headline}**](${s.link})${ts}`;
      else        md += `- **${s.headline}**`;
      if (s.detail) md += ` — ${s.detail}`;
      md += `\n`;
    }
    md += '\n';
  } else {
    md += '\n_No insights extracted._\n\n';
  }
}
if (pending) md += `\n_${pending} video(s) waiting for transcripts — will retry at the next digest._\n`;
if (hw) md += `\n${hw}\n`;

// ---- HTML ----
let html = `<div style="font-family:Arial,Helvetica,sans-serif;font-size:14px;line-height:1.5;">`;
html += `<h2 style="margin:0 0 8px 0;">Daily Podcast Insights</h2>`;
html += `<p style="color:#666;margin:0 0 14px 0;">Total videos: ${videos.length}</p>`;
for (const v of videos) {
  const htmlHeading = v.channelName ? `${esc(v.channelName)} · ${esc(v.title)}` : esc(v.title);
  html += `<h3 style="font-size:15px;margin:18px 0 6px 0;">`;
  html += v.url
    ? `<a href="${esc(v.url)}" target="_blank" style="color:#1a73e8;text-decoration:none;">${htmlHeading}</a>`
    : htmlHeading;
  html += `</h3>`;
  if (v.guests && v.guests.length) html += `<p style="margin:0 0 6px 0;color:#666;font-style:italic;">with ${esc(v.guests.join(', '))}</p>`;
  if (v.summary) html += `<p style="margin:6px 0 10px 0;color:#222;">${esc(v.summary)}</p>`;
  if (v.insights.length) {
    html += `<ul style="margin:6px 0 14px 18px;padding:0;">`;
    for (const s of v.insights) {
      html += `<li style="margin-bottom:12px;color:#111;">`;
      const label = `<strong>${esc(s.headline)}</strong>`;
      html += s.link
        ? `<a href="${esc(s.link)}" target="_blank" style="color:#1a73e8;text-decoration:none;">${label}</a>`
        : label;
      if (s.tSeconds != null && s.link) {
        html += ` <a href="${esc(s.link)}" target="_blank" style="color:#888;text-decoration:none;font-size:12px;white-space:nowrap;">&#9654; ${hhmmss(s.tSeconds)}</a>`;
      }
      if (s.detail) html += `<br><span style="color:#333;">${esc(s.detail)}</span>`;
      html += `</li>`;
    }
    html += `</ul>`;
  } else {
    html += `<p style="color:#666;margin-bottom:12px;"><em>No insights extracted.</em></p>`;
  }
}
if (pending) html += `<p style="color:#666;"><em>${pending} video(s) waiting for transcripts — will retry at the next digest.</em></p>`;
if (hw) html += `<p style="color:#b00;">${esc(hw)}</p>`;
html += `<hr style="border:none;border-top:1px solid #eee;margin:12px 0;">`;
html += `<p style="font-size:12px;color:#999;margin:8px 0 0 0;">Generated automatically</p></div>`;

return [{ json: { digestMarkdown: md, digestHtml: html, count: videos.length, pending, videos } }];

// Build Telegram message(s). Tracks which videoIds are inside each message so
// 'Mark sent' can update the ledger only for messages that actually delivered.
function esc(s) {
  return (s || '').toString().replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
}
function hhmmss(sec) {
  if (sec == null || isNaN(sec)) return '';
  sec = Math.floor(sec);
  const h = Math.floor(sec/3600), m = Math.floor((sec%3600)/60), s = sec%60;
  const mm = String(m).padStart(2,'0'), ss = String(s).padStart(2,'0');
  return h ? `${h}:${mm}:${ss}` : `${m}:${ss}`;
}
function tighten(text, maxChars) {
  if (!text) return '';
  const t = text.replace(/\s+/g, ' ').trim();
  if (t.length <= maxChars) return t;
  const sentences = t.match(/[^.!?]+[.!?]+|[^.!?]+$/g) || [t];
  let acc = '';
  for (const s of sentences) {
    const next = acc ? acc + ' ' + s.trim() : s.trim();
    if (next.length > maxChars) break;
    acc = next;
  }
  if (!acc) acc = t.slice(0, maxChars - 1).replace(/\s+\S*$/, '') + '…';
  return acc;
}

const SOFT_LIMIT   = 3800;
const HOOK_MAX     = 180;
const DETAIL_MAX   = 240;
const MAX_TAKEAWAYS = 5;

const blocks = [];
const seen = new Set();
let pending = 0;

for (const it of items) {
  const row = it.json || {};
  if (row._omit) { if (row._pending) pending++; continue; }
  const obj = row.insightsObj;
  if (!obj) continue;

  const title = (obj.videoTitle || row.title || 'Untitled').toString();
  const url   = (obj.videoUrl   || row.url   || '').toString();
  const key   = (url || title).toLowerCase();
  if (seen.has(key)) continue;
  seen.add(key);

  const summary  = (obj.summary || '').toString().trim();
  const hook     = tighten(summary, HOOK_MAX);
  const insights = Array.isArray(obj.insights) ? obj.insights.slice(0, MAX_TAKEAWAYS) : [];

  const channelName = (obj.channelName || row.channelName || '').toString().trim();
  const guests      = Array.isArray(obj.guests) ? obj.guests.filter(g => typeof g === 'string' && g.trim()) : [];
  const channelPrefix = channelName ? `<b>${esc(channelName)}</b> · ` : '';
  let block = `🎙 ${channelPrefix}<b><a href="${esc(url)}">${esc(title)}</a></b>\n`;
  if (guests.length) block += `<i>with ${esc(guests.join(', '))}</i>\n`;
  if (hook) block += `${esc(hook)}\n`;
  if (insights.length) {
    block += `\n`;
    for (const s of insights) {
      const headline = (s.headline || '').toString().trim();
      const detail   = tighten((s.detail || '').toString().trim(), DETAIL_MAX);
      const link     = (s.link || '').toString().trim();
      const tSec     = (s.tSeconds == null ? null : Number(s.tSeconds));
      if (!headline && !detail) continue;
      block += `→ <b>${esc(headline)}</b>`;
      if (detail) block += ` — ${esc(detail)}`;
      if (link && tSec != null && isFinite(tSec)) {
        block += ` <a href="${esc(link)}">[${esc(hhmmss(tSec))}]</a>`;
      }
      block += `\n`;
    }
  }
  blocks.push({ html: block.trim(), videoId: (row.videoId || '').toString() });
}

let hw = '';
try { hw = ($('Load unsent').first().json._healthWarning || '').toString(); } catch (e) {}

let footer = '';
if (pending) footer += `\n\n⏳ ${pending} video(s) waiting for transcripts — will retry at the next digest.`;
if (hw) footer += `\n\n${hw}`;

if (!blocks.length) {
  let txt = `<b>🎧 Daily Podcast Insights</b>\n<i>No new episode summaries this morning.</i>${footer}`;
  return [{ json: { telegramHtml: txt, messageIndex: 0, messageCount: 1, videoIds: [] } }];
}

const HEADER = `<b>🎧 Daily Podcast Insights</b>\n<i>${blocks.length} ${blocks.length === 1 ? 'episode' : 'episodes'}</i>`;
const messages = [];
let current = HEADER;
let currentIds = [];
for (const b of blocks) {
  const joined = `${current}\n\n${b.html}`;
  if (joined.length > SOFT_LIMIT && current !== HEADER) {
    messages.push({ html: current, videoIds: currentIds });
    current = b.html;
    currentIds = [b.videoId];
  } else {
    current = joined;
    currentIds.push(b.videoId);
  }
}
if (current && current !== HEADER) messages.push({ html: current, videoIds: currentIds });

if (footer && messages.length) messages[messages.length - 1].html += footer;

return messages.map((m, i) => ({
  json: { telegramHtml: m.html, messageIndex: i, messageCount: messages.length, videoIds: m.videoIds.filter(Boolean) }
}));

// Mark videos as sent in the ledger — only for Telegram messages that
// actually delivered. Failed messages leave their videos 'discovered',
// so the next digest retries them automatically.
const sd = $getWorkflowStaticData('global');
if (!sd.videos) sd.videos = {};
const built = $('Build Telegram Digest').all();
const now = Date.now();
let marked = 0;
const failedMessages = [];
items.forEach((it, i) => {
  const r = it.json || {};
  const failed = !!r.error || r.ok === false;
  if (failed) { failedMessages.push(i); return; }
  const ids = (built[i] && built[i].json && built[i].json.videoIds) || [];
  for (const id of ids) {
    if (sd.videos[id]) { sd.videos[id].status = 'sent'; sd.videos[id].sentAtMs = now; marked++; }
  }
});
return [{ json: { marked, failedMessages } }];

// Side-channel capture for the podcast knowledge base (automations/podcast-knowledge).
// Reads the pristine per-video output of 'Resolve insights' (has videoId + anchorQuote,
// which Build Digest drops) and emits one JSON file for the morning's digest, to be PUT
// into the repo at context/knowledge/podcasts/_inbox/<runStamp>.json.
function toISODate(v) {
  if (v == null || v === '') return null;
  let n = Number(v);
  if (!isNaN(n) && n > 0) { if (n < 1e12) n = n * 1000; const d = new Date(n); if (!isNaN(d.getTime())) return d.toISOString().slice(0, 10); }
  const d2 = new Date(v); return isNaN(d2.getTime()) ? null : d2.toISOString().slice(0, 10);
}
const now = new Date();
const runStamp = now.toISOString().replace(/[-:]/g, '').slice(0, 13); // e.g. 20260611T0700
let rows = [];
try { rows = $('Resolve insights').all().map(it => it.json); } catch (e) { rows = []; }
const episodes = rows
  .filter(r => r && r.insightsObj && !r._omit && Array.isArray(r.insightsObj.insights) && r.insightsObj.insights.length)
  .map(r => {
    const o = r.insightsObj;
    return {
      videoId: r.videoId || '',
      videoTitle: o.videoTitle || r.title || '',
      videoUrl: o.videoUrl || r.url || '',
      channelName: o.channelName || r.channelName || '',
      publishedDate: toISODate(r.published),
      guests: Array.isArray(o.guests) ? o.guests : [],
      summary: o.summary || '',
      insights: (o.insights || []).map(i => ({
        headline: i.headline || '',
        detail: i.detail || '',
        anchorQuote: i.anchorQuote || '',
        tSeconds: (i.tSeconds == null ? null : i.tSeconds),
        link: i.link || ''
      }))
    };
  });
if (!episodes.length) return [];
const payload = { schema: 1, generatedAt: now.toISOString(), runStamp: runStamp, episodes: episodes };
const path = 'context/knowledge/podcasts/_inbox/' + runStamp + '.json';
const content = Buffer.from(JSON.stringify(payload, null, 2)).toString('base64');
return [{ json: { path: path, content: content, message: 'feat(podcasts): capture digest ' + runStamp } }];
